const state = $('Read State').first().json.content || '';
const contentStrategy = $('Read Content Strategy').first().json.content || '';
const contentStrategySha = $('Read Content Strategy').first().json.sha || '';
const plan = $('Read Weekly Plan').first().json.content || '';

return [{
  json: {
    businessId: 'bayflow',
    businessPath: 'memory-bank/businesses/bayflow',
    contentStrategySha: contentStrategySha,
    prompt: `Today is ${new Date().toISOString().split('T')[0]}. You are the Marketing Agent for BayFlow (auto repair shop software).

You are the most critical revenue agent. Your job is SEO, distribution, social scheduling, and directory submissions.

## Current State
${state}

## Content Strategy
${contentStrategy}

## Weekly Plan
${plan}

Perform your weekly marketing review:

1. **SEO Assessment:** Review which keywords we're targeting, assess ranking potential, identify new keyword opportunities. Check if published blog posts cover our target keywords.

2. **Content Distribution:** For each published blog post, recommend parasite SEO actions (repurpose to Medium, LinkedIn articles, Reddit posts with backlinks to main site).

3. **Directory Submissions:** Check which directories we should submit to (G2, Capterra, GetApp, Product Hunt upcoming, SaaSHub, AlternativeTo). List specific actions.

4. **Social Media:** Recommend social posting schedule for the week. Which platforms, what content to post, when.

5. **Google Search Console:** Recommend pages to submit for indexing.

6. **Recommendations:** What should the Content Agent produce next week based on SEO gaps?

Output your report in the structured format: Agent name, business, date, status (GREEN/YELLOW/RED), key metrics with trends, actions taken, issues detected, recommendations, needs from CEO Agent.

AFTER your main report, you MUST output an updated version of the content-strategy.md file. This updated version should incorporate your recommendations, update keyword priorities, adjust the editorial calendar, and reflect any new SEO insights from this week's analysis. Output it between these exact delimiters:

===CONTENT_STRATEGY_UPDATE_START===
(full updated content-strategy.md content here)
===CONTENT_STRATEGY_UPDATE_END===`
  }
}];

const llmOutput = $('Marketing LLM Chain').first().json.text || '';
const contentStrategySha = $('Build Marketing Prompt').first().json.contentStrategySha || '';
const today = new Date().toISOString().split('T')[0];

// Extract content strategy update
let contentStrategyUpdate = '';
const startDelimiter = '===CONTENT_STRATEGY_UPDATE_START===';
const endDelimiter = '===CONTENT_STRATEGY_UPDATE_END===';
const startIdx = llmOutput.indexOf(startDelimiter);
const endIdx = llmOutput.indexOf(endDelimiter);

if (startIdx !== -1 && endIdx !== -1) {
  contentStrategyUpdate = llmOutput.substring(startIdx + startDelimiter.length, endIdx).trim();
}

// Extract marketing report (everything before the content strategy delimiter)
let marketingReport = llmOutput;
if (startIdx !== -1) {
  marketingReport = llmOutput.substring(0, startIdx).trim();
}

return [{
  json: {
    marketingReport: marketingReport,
    contentStrategyUpdate: contentStrategyUpdate,
    contentStrategySha: contentStrategySha,
    reportDate: today
  }
}];
